/**
 * ID Type Code Generator — Proactive Enforcer for ADR-0001 (ID Taxonomy)
 *
 * Trinity Role: Enforcer-Proactive
 * Contract: ID Taxonomy (docs/adr/0001-id-taxonomy.md)
 *
 * This script generates typed ID accessor functions for all entity types,
 * making it structurally impossible to use raw strings as entity IDs.
 * The generated API accepts only the correct typed ID — passing a raw string
 * is a compile-time error.
 *
 * Outputs: packages/<pkg>/src/generated/id-types.ts for each package
 *
 * Usage: npx ts-node scripts/gen-id-types.ts
 */

import * as fs from 'fs';
import * as path from 'path';

const ENTITY_TYPES = [
  { name: 'Patient', prefix: 'pat:', pkg: 'pvs-charly' },
  { name: 'Appointment', prefix: 'appt:', pkg: 'pvs-charly' },
  { name: 'Prescription', prefix: 'rx:', pkg: 'pvs-x-isynet' },
];

function generateIdHelper(entityName: string, prefix: string): string {
  return `
// Generated by scripts/gen-id-types.ts — DO NOT EDIT MANUALLY
// Contract: ID Taxonomy (ADR-0001)

export type ${entityName}Id = \`${prefix}\${string}\`;

export function make${entityName}Id(raw: string): ${entityName}Id {
  if (raw.startsWith('${prefix}')) {
    return raw as ${entityName}Id;
  }
  return \`${prefix}\${raw}\` as ${entityName}Id;
}

export function is${entityName}Id(value: string): value is ${entityName}Id {
  return value.startsWith('${prefix}');
}
`.trim();
}

function main(): void {
  for (const entity of ENTITY_TYPES) {
    const outputDir = path.join(
      'packages',
      entity.pkg,
      'src',
      'generated'
    );
    const outputFile = path.join(outputDir, `${entity.name.toLowerCase()}-id.ts`);

    fs.mkdirSync(outputDir, { recursive: true });
    fs.writeFileSync(outputFile, generateIdHelper(entity.name, entity.prefix));
    console.log(`Generated: ${outputFile}`);
  }
}

main();
